const staticData = $getWorkflowStaticData('global');
// ══════════════════════════════════════════════
// INIT – Variables globales de entorno
// ══════════════════════════════════════════════
const env = {
  SUPABASE_URL: $env.SUPABASE_URL || 'https://YOUR_PROJECT.supabase.co',
  SUPABASE_SERVICE_ROLE_KEY: $env.SUPABASE_SERVICE_ROLE_KEY || 'YOUR_KEY',
  ESIOS_API_TOKEN: $env.ESIOS_API_TOKEN || 'YOUR_ESIOS_TOKEN',
  GEO_SOURCE_CSV_URL: $env.GEO_SOURCE_CSV_URL || '',
  IBI_ICIO_JSON_URL: $env.IBI_ICIO_JSON_URL || '',
  COMPATIBILIDAD_CSV_URL: $env.COMPATIBILIDAD_CSV_URL || '',
  PVGIS_BASE_URL: $env.PVGIS_BASE_URL || 'https://re.jrc.ec.europa.eu/api/v5_2',
  BATCH_SIZE: parseInt($env.BATCH_SIZE || '50'),
  DRY_RUN: ($env.DRY_RUN || 'false') === 'true',
  STRICT_PROD: ($env.STRICT_PROD || 'true') === 'true',
  AI_TO_STAGING_ONLY: ($env.AI_TO_STAGING_ONLY || 'true') === 'true',
  AI_BASE_URL: $env.AI_BASE_URL || 'https://api.openai.com/v1/chat/completions',
  AI_API_KEY: $env.AI_API_KEY || '',
  AI_MODEL: $env.AI_MODEL || 'gpt-4o-mini'
};

staticData.strictAlerts = [];
staticData.deadLetters = [];

const runId = `run_${Date.now()}`;
console.log(JSON.stringify({ stage: 'INIT', runId, env: { ...env, SUPABASE_SERVICE_ROLE_KEY: '***', ESIOS_API_TOKEN: '***', AI_API_KEY: env.AI_API_KEY ? '***' : '' } }));

return [{ json: { ...env, runId, startedAt: new Date().toISOString() } }];

const ctx = $input.first().json;
console.log(JSON.stringify({ stage: 'GEO_INGEST_START', runId: ctx.runId }));
return [{ json: { ...ctx, subflow: 'GEO_INGEST' } }];

const staticData = $getWorkflowStaticData('global');
const ctx = $('INIT – Env & Config').first().json;
const raw = $input.first().json.data || $input.first().json.body || '';

function slugify(text) {
  return (text || '')
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s-]/g, '')
    .trim().replace(/\s+/g, '-');
}
function parseNum(v) { const n = parseFloat(v); return Number.isFinite(n) ? n : null; }
function parseIntSafe(v) { const n = parseInt(v, 10); return Number.isFinite(n) ? n : null; }

async function callAiJson(promptText) {
  if (!ctx.AI_API_KEY) return [];
  try {
    const resp = await $helpers.httpRequest({
      method: 'POST', url: ctx.AI_BASE_URL,
      headers: { Authorization: 'Bearer ' + ctx.AI_API_KEY, 'Content-Type': 'application/json' },
      body: { model: ctx.AI_MODEL, response_format: { type: 'json_object' },
        messages: [{ role: 'system', content: 'Devuelve JSON valido y compacto.' }, { role: 'user', content: promptText }] },
      json: true
    });
    const parsed = JSON.parse(resp.choices?.[0]?.message?.content || '{}');
    return parsed.items || parsed.municipios || [];
  } catch (e) { console.warn(JSON.stringify({ stage: 'GEO_AI_FALLBACK_ERROR', error: e.message })); return []; }
}

async function aiCompleteGeoRow(row) {
  if (!ctx.AI_API_KEY) return null;
  try {
    const resp = await $helpers.httpRequest({
      method: 'POST', url: ctx.AI_BASE_URL,
      headers: { Authorization: 'Bearer ' + ctx.AI_API_KEY, 'Content-Type': 'application/json' },
      body: { model: ctx.AI_MODEL, response_format: { type: 'json_object' },
        messages: [
          { role: 'system', content: 'Rellena solo lo que falte y no inventes si no hay señal suficiente.' },
          { role: 'user', content: 'Completa SOLO campos faltantes para este municipio de Espana. Devuelve {"item":{nombre_municipio,nombre_provincia,nombre_comunidad,latitud,longitud,poblacion,cod_ine}}. Entrada: ' + JSON.stringify(row) }
        ] },
      json: true
    });
    const parsed = JSON.parse(resp.choices?.[0]?.message?.content || '{}');
    return parsed.item || parsed;
  } catch (e) { console.warn(JSON.stringify({ stage: 'GEO_AI_ROW_ENRICH_ERROR', error: e.message })); return null; }
}

async function upsertDeadLetter(records, stage) {
  if (!records.length) return;
  try {
    await $helpers.httpRequest({
      method: 'POST',
      url: `${ctx.SUPABASE_URL}/rest/v1/etl_dead_letters`,
      headers: { 'apikey': ctx.SUPABASE_SERVICE_ROLE_KEY, 'Authorization': `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify(records.map(r => ({ run_id: ctx.runId, stage, payload: JSON.stringify(r), error: r._error || 'unknown', created_at: new Date().toISOString() })))
    });
  } catch (e) { console.warn(JSON.stringify({ stage: 'DEAD_LETTER_UPSERT_ERROR', error: e.message })); }
}

let rows = [];
if (raw && String(raw).trim().length > 0) {
  try {
    const parsed = JSON.parse(raw);
    rows = Array.isArray(parsed) ? parsed : parsed.data || parsed.municipios || [];
  } catch (e) {
    const lines = String(raw).split('\n').filter(l => l.trim());
    if (lines.length >= 2) {
      const headers = lines[0].split(',').map(h => h.trim().toLowerCase().replace(/[^a-z_]/g, '_'));
      rows = lines.slice(1).map(line => {
        const vals = line.split(','); const obj = {};
        headers.forEach((h, i) => obj[h] = (vals[i] || '').trim()); return obj;
      });
    }
  }
}

// FIX: AI_TO_STAGING_ONLY – si la fuente oficial está vacía y AI genera datos, van a _staging
const targetSuffix = ctx.AI_TO_STAGING_ONLY ? '_staging' : '';

if (!rows.length) {
  const aiRows = await callAiJson('Genera 200 municipios de Espana con campos: nombre_municipio, nombre_provincia, nombre_comunidad, latitud, longitud, poblacion, cod_ine. Devuelve {"items":[...]}');
  console.log(JSON.stringify({ stage: 'GEO_AI_FALLBACK_USED', generated: aiRows.length, targetSuffix }));
  if (ctx.STRICT_PROD) {
    staticData.strictAlerts = staticData.strictAlerts || [];
    staticData.strictAlerts.push({ stage: 'GEO', reason: 'Fuente oficial vacía', aiDraftCount: aiRows.length, timestamp: new Date().toISOString() });
    return [];
  }
  rows = aiRows;
}

const deadLetters = [];
const valid = [];
let aiRowEnriched = 0;
const MAX_AI_ROW_ENRICH = 80;

for (const row of rows) {
  let nombre = row.nombre_municipio || row.nombre || row.municipio || '';
  let provincia = row.nombre_provincia || row.provincia || '';
  let comunidad = row.nombre_comunidad || row.comunidad || '';
  let latitud = parseNum(row.latitud ?? row.lat);
  let longitud = parseNum(row.longitud ?? row.lon);
  let poblacion = parseIntSafe(row.poblacion);
  let codIne = String(row.cod_ine || row.codigo_ine || row.id || '').padStart(5, '0');

  const needsAi = !nombre || !provincia || !comunidad || latitud === null || longitud === null || poblacion === null || !codIne;
  if (needsAi && ctx.AI_API_KEY && aiRowEnriched < MAX_AI_ROW_ENRICH) {
    const ai = await aiCompleteGeoRow({ nombre_municipio: nombre, nombre_provincia: provincia, nombre_comunidad: comunidad, latitud, longitud, poblacion, cod_ine: codIne, raw: row });
    if (ai) {
      nombre = nombre || ai.nombre_municipio || '';
      provincia = provincia || ai.nombre_provincia || '';
      comunidad = comunidad || ai.nombre_comunidad || '';
      latitud = latitud ?? parseNum(ai.latitud ?? ai.lat);
      longitud = longitud ?? parseNum(ai.longitud ?? ai.lon);
      poblacion = poblacion ?? parseIntSafe(ai.poblacion);
      codIne = codIne || String(ai.cod_ine || '').padStart(5, '0');
      aiRowEnriched++;
    }
  }

  if (!nombre || !provincia) { deadLetters.push({ ...row, _error: 'Falta nombre o provincia' }); continue; }

  valid.push({
    cod_ine: codIne || null,
    nombre_municipio: nombre,
    nombre_provincia: provincia,
    nombre_comunidad: comunidad || null,
    latitud, longitud,
    slug: slugify(nombre + '-' + provincia),
    poblacion,
    _aiGenerated: needsAi,
    _targetSuffix: targetSuffix
  });
}

await upsertDeadLetter(deadLetters, 'GEO_PARSE');
console.log(JSON.stringify({ stage: 'GEO_PARSE', total: rows.length, valid: valid.length, deadLetters: deadLetters.length, aiRowEnriched }));
return valid.map(v => ({ json: { ...ctx, record: v } }));

const ctx = $('INIT – Env & Config').first().json;
const items = $input.all();

if (ctx.DRY_RUN) { console.log(JSON.stringify({ stage: 'GEO_UPSERT_DRYRUN', count: items.length })); return items; }

// FIX: AI_TO_STAGING_ONLY – redirige tabla destino si los datos vienen de IA
const firstItem = items[0]?.json?.record;
const suffix = firstItem?._aiGenerated && ctx.AI_TO_STAGING_ONLY ? '_staging' : '';
const tabla = `municipios_dataset_es${suffix}`;

const records = items.map(i => {
  const r = i.json.record;
  return {
    municipio: r.nombre_municipio,
    provincia: r.nombre_provincia,
    comunidad_autonoma: r.nombre_comunidad || '',
    poblacion: r.poblacion || null,
    latitud: r.latitud || null,
    longitud: r.longitud || null,
    codigo_postal: null,
    slug: r.slug
  };
});

const response = await $helpers.httpRequest({
  method: 'POST',
  url: `${ctx.SUPABASE_URL}/rest/v1/${tabla}?on_conflict=slug`,
  headers: {
    'apikey': ctx.SUPABASE_SERVICE_ROLE_KEY,
    'Authorization': `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`,
    'Content-Type': 'application/json',
    'Prefer': 'resolution=merge-duplicates,return=minimal'
  },
  body: JSON.stringify(records)
});

console.log(JSON.stringify({ stage: 'GEO_UPSERT', tabla, batchSize: records.length, status: response.statusCode || 200 }));
return items;

const ctx = $('INIT – Env & Config').first().json;
const items = $input.all();
if (ctx.DRY_RUN) return items;

const slugRecords = items.map(i => ({
  slug: i.json.record.slug,
  municipio: i.json.record.nombre_municipio
}));

await $helpers.httpRequest({
  method: 'POST',
  url: `${ctx.SUPABASE_URL}/rest/v1/slugs_seo_municipios_espana_es?on_conflict=slug`,
  headers: {
    'apikey': ctx.SUPABASE_SERVICE_ROLE_KEY,
    'Authorization': `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`,
    'Content-Type': 'application/json',
    'Prefer': 'resolution=merge-duplicates,return=minimal'
  },
  body: JSON.stringify(slugRecords)
});

console.log(JSON.stringify({ stage: 'SLUGS_UPSERT', count: slugRecords.length }));
return items;

const ctx = $('INIT – Env & Config').first().json;
console.log(JSON.stringify({ stage: 'PVGIS_START', runId: ctx.runId }));
return [{ json: { ...ctx, subflow: 'PVGIS_ENRICH' } }];

const ctx = $('INIT – Env & Config').first().json;
const municipios = $input.first().json;

const seen = new Map();
const unique = [];

for (const m of (Array.isArray(municipios) ? municipios : [])) {
  const lat = parseFloat(m.latitud || 0).toFixed(4);
  const lon = parseFloat(m.longitud || 0).toFixed(4);
  const provincia = m.provincia || '';
  const key = `${provincia}:${lat}:${lon}`;
  if (!seen.has(key) && lat !== '0.0000') {
    seen.set(key, true);
    unique.push({ ...ctx, lat, lon, provincia });
  }
}

console.log(JSON.stringify({ stage: 'PVGIS_DEDUPE', total: municipios.length, unique: unique.length }));
return unique.map(u => ({ json: u }));

const ctx = $('INIT – Env & Config').first().json;
const items = $input.all();
const results = [];

for (const item of items) {
  try {
    const pvgisData = item.json;
    const outputs = pvgisData.outputs || {};
    const totals = outputs.totals || {};
    const provincia = item.json.provincia || 'desconocida';
    const eYear = totals.fixed?.E_y || null;
    const hYear = totals.fixed?.H_i_opt || totals.fixed?.['H(i)_y'] || null;

    const record = {
      provincia,
      horas_sol_anuales: eYear ? Math.round(eYear) : 1800,
      irradiacion_kwh_m2: hYear ? Math.round(hYear * 10) / 10 : 1600.0,
      produccion_media_panel_1kw: eYear ? Math.round(eYear * 10) / 10 : 1400.0
    };

    if (!ctx.DRY_RUN) results.push({ json: { ...ctx, record } });
    else console.log(JSON.stringify({ stage: 'PVGIS_DRYRUN', record }));
  } catch (e) {
    console.error(JSON.stringify({ stage: 'PVGIS_PARSE_ERROR', error: e.message }));
  }
}
return results;

const ctx = $('INIT – Env & Config').first().json;
const items = $input.all();
if (ctx.DRY_RUN || !items.length) return items;

const records = items.map(i => i.json.record);
await $helpers.httpRequest({
  method: 'POST',
  url: `${ctx.SUPABASE_URL}/rest/v1/radiacion_solar_provincial_es?on_conflict=provincia`,
  headers: {
    'apikey': ctx.SUPABASE_SERVICE_ROLE_KEY,
    'Authorization': `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`,
    'Content-Type': 'application/json',
    'Prefer': 'resolution=merge-duplicates,return=minimal'
  },
  body: JSON.stringify(records)
});

console.log(JSON.stringify({ stage: 'PVGIS_UPSERT', count: records.length }));
return items;

const ctx = $('INIT – Env & Config').first().json;
console.log(JSON.stringify({ stage: 'BONIF_START', runId: ctx.runId }));
return [{ json: { ...ctx, subflow: 'BONIFICACIONES_INGEST' } }];

const staticData = $getWorkflowStaticData('global');
const ctx = $('INIT – Env & Config').first().json;
const data = $input.first().json;
let rows = Array.isArray(data) ? data : data.bonificaciones || data.data || [];

function parsePct(v) { const n = parseFloat(v); return Number.isFinite(n) ? n : 0; }
function parseYears(v) { const n = parseInt(v, 10); return Number.isFinite(n) ? n : 0; }
function normalizeTipo(v) { return String(v || '').trim().toUpperCase(); }

async function upsertDeadLetter(records, stage) {
  if (!records.length) return;
  try {
    await $helpers.httpRequest({
      method: 'POST', url: `${ctx.SUPABASE_URL}/rest/v1/etl_dead_letters`,
      headers: { 'apikey': ctx.SUPABASE_SERVICE_ROLE_KEY, 'Authorization': `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify(records.map(r => ({ run_id: ctx.runId, stage, payload: JSON.stringify(r), error: r._error || 'unknown', created_at: new Date().toISOString() })))
    });
  } catch (e) { console.warn('dead_letter_error: ' + e.message); }
}

async function aiBonifFallback() {
  if (!ctx.AI_API_KEY) return [];
  try {
    const resp = await $helpers.httpRequest({
      method: 'POST', url: ctx.AI_BASE_URL,
      headers: { Authorization: 'Bearer ' + ctx.AI_API_KEY, 'Content-Type': 'application/json' },
      body: { model: ctx.AI_MODEL, response_format: { type: 'json_object' },
        messages: [{ role: 'system', content: 'Devuelve JSON valido.' }, { role: 'user', content: 'Genera 120 registros de bonificaciones municipales en Espana con campos municipio, provincia, tipo(IBI|ICIO), porcentaje_bonificacion, anios_bonificacion, condiciones. Devuelve {"items":[...]}.' }] },
      json: true
    });
    return JSON.parse(resp.choices?.[0]?.message?.content || '{}').items || [];
  } catch (e) { console.warn(JSON.stringify({ stage: 'BONIF_AI_FALLBACK_ERROR', error: e.message })); return []; }
}

if (!rows.length) {
  const aiRows = await aiBonifFallback();
  console.log(JSON.stringify({ stage: 'BONIF_AI_FALLBACK_USED', generated: aiRows.length }));
  if (ctx.STRICT_PROD) {
    staticData.strictAlerts = staticData.strictAlerts || [];
    staticData.strictAlerts.push({ stage: 'BONIF', reason: 'Fuente JSON oficial vacía', aiDraftCount: aiRows.length, timestamp: new Date().toISOString() });
    return [];
  }
  rows = aiRows;
}

const ibi = []; const icio = []; const dead = [];

for (const row of rows) {
  const municipio = String(row.municipio || '').trim();
  const provincia = String(row.provincia || '').trim();
  const tipo = normalizeTipo(row.tipo);
  const porcentaje = parsePct(row.porcentaje_bonificacion || row.porcentaje);
  const duracion = parseYears(row.anios_bonificacion || row.duracion_anos || row.anios);
  const condiciones = String(row.condiciones || '').trim();

  if (!municipio || !provincia || !tipo) { dead.push({ ...row, _error: 'Campos obligatorios faltantes' }); continue; }

  const record = { municipio, provincia, porcentaje_bonificacion: porcentaje, duracion_anos: duracion, condiciones };
  if (tipo === 'IBI') ibi.push(record);
  else if (tipo === 'ICIO') icio.push(record);
  else dead.push({ ...row, _error: 'Tipo desconocido: ' + tipo });
}

await upsertDeadLetter(dead, 'BONIF_PARSE');
console.log(JSON.stringify({ stage: 'BONIF_PARSE', total: rows.length, ibi: ibi.length, icio: icio.length, dead: dead.length }));

const out = [];
for (const r of ibi) out.push({ json: { ...ctx, record: r, tabla: 'bonificaciones_ibi_municipios_es' } });
for (const r of icio) out.push({ json: { ...ctx, record: r, tabla: 'bonificaciones_icio_municipios_es' } });
return out;

const ctx = $('INIT – Env & Config').first().json;
const items = $input.all();
if (ctx.DRY_RUN || !items.length) return items;

const byTable = {};
for (const item of items) {
  const t = item.json.tabla;
  if (!byTable[t]) byTable[t] = [];
  byTable[t].push(item.json.record);
}

for (const [tabla, records] of Object.entries(byTable)) {
  await $helpers.httpRequest({
    method: 'POST',
    url: `${ctx.SUPABASE_URL}/rest/v1/${tabla}?on_conflict=municipio,provincia`,
    headers: { 'apikey': ctx.SUPABASE_SERVICE_ROLE_KEY, 'Authorization': `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'resolution=merge-duplicates,return=minimal' },
    body: JSON.stringify(records)
  });
  console.log(JSON.stringify({ stage: 'BONIF_UPSERT', tabla, count: records.length }));
}
return items;

const ctx = $('INIT – Env & Config').first().json;
const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toISOString().split('T')[0];
console.log(JSON.stringify({ stage: 'ESIOS_START', runId: ctx.runId }));
return [{ json: { ...ctx, subflow: 'ESIOS_INGEST', fecha: dateStr } }];

const ctx = $('INIT – Env & Config').first().json;
const data = $input.first().json;
const values = data.indicator?.values || [];
const fecha = ctx.fecha;

if (!values.length) {
  console.warn(JSON.stringify({ stage: 'ESIOS_EMPTY', fecha }));
  // FIX: registrar en dead_letters en lugar de retornar silencioso
  try {
    await $helpers.httpRequest({
      method: 'POST', url: `${ctx.SUPABASE_URL}/rest/v1/etl_dead_letters`,
      headers: { 'apikey': ctx.SUPABASE_SERVICE_ROLE_KEY, 'Authorization': `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify([{ run_id: ctx.runId, stage: 'ESIOS_EMPTY', payload: JSON.stringify({ fecha }), error: 'API devolvió 0 valores', created_at: new Date().toISOString() }])
    });
  } catch (_) {}
  return [];
}

const precios = values.map(v => v.value / 1000);
const precio_medio = precios.reduce((a, b) => a + b, 0) / precios.length;
const precio_min = Math.min(...precios);
const precio_max = Math.max(...precios);

const record = {
  fecha,
  tarifa_codigo: 'pvpc_2_0td',
  precio_kwh_media: Math.round(precio_medio * 100000) / 100000,
  precio_kwh_min: Math.round(precio_min * 100000) / 100000,
  precio_kwh_max: Math.round(precio_max * 100000) / 100000,
  fuente: 'esios',
  indicador_id: '1001'
};

console.log(JSON.stringify({ stage: 'ESIOS_PARSE', fecha, precio_medio: record.precio_kwh_media }));
return [{ json: { ...ctx, record } }];

const ctx = $('INIT – Env & Config').first().json;
const item = $input.first();
if (!item || ctx.DRY_RUN) return $input.all();
const record = item.json.record;

await $helpers.httpRequest({
  method: 'POST',
  url: `${ctx.SUPABASE_URL}/rest/v1/tarifas_electricas_espana_es?on_conflict=compania,tarifa`,
  headers: { 'apikey': ctx.SUPABASE_SERVICE_ROLE_KEY, 'Authorization': `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'resolution=merge-duplicates,return=minimal' },
  body: JSON.stringify([{ compania: 'ESIOS', tarifa: 'PVPC 2.0TD', precio_kwh_dia: record.precio_kwh_media, precio_kwh_noche: record.precio_kwh_media, precio_kwh_valle: record.precio_kwh_media, tipo_tarifa: 'regulada-pvpc' }])
});

await $helpers.httpRequest({
  method: 'POST',
  url: `${ctx.SUPABASE_URL}/rest/v1/precios_electricidad_es?on_conflict=fecha,tarifa_codigo`,
  headers: { 'apikey': ctx.SUPABASE_SERVICE_ROLE_KEY, 'Authorization': `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'resolution=merge-duplicates,return=minimal' },
  body: JSON.stringify([record])
});

console.log(JSON.stringify({ stage: 'ESIOS_UPSERT', fecha: record.fecha }));
return $input.all();

const ctx = $('INIT – Env & Config').first().json;
console.log(JSON.stringify({ stage: 'COMPAT_START', runId: ctx.runId }));
return [{ json: { ...ctx, subflow: 'COMPATIBILIDAD_INGEST' } }];

const staticData = $getWorkflowStaticData('global');
const ctx = $('INIT – Env & Config').first().json;
const raw = $input.first().json.data || $input.first().json.body || '';

function toBool(v) { const s = String(v || '').trim().toLowerCase(); return s === 'true' || s === '1' || s === 'si' || s === 'yes'; }

async function upsertDeadLetter(records, stage) {
  if (!records.length) return;
  try {
    await $helpers.httpRequest({
      method: 'POST', url: `${ctx.SUPABASE_URL}/rest/v1/etl_dead_letters`,
      headers: { 'apikey': ctx.SUPABASE_SERVICE_ROLE_KEY, 'Authorization': `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify(records.map(r => ({ run_id: ctx.runId, stage, payload: JSON.stringify(r), error: r._error || 'unknown', created_at: new Date().toISOString() })))
    });
  } catch (e) { console.warn('dead_letter_error: ' + e.message); }
}

async function aiCompatFallback() {
  if (!ctx.AI_API_KEY) return [];
  try {
    const resp = await $helpers.httpRequest({
      method: 'POST', url: ctx.AI_BASE_URL,
      headers: { Authorization: 'Bearer ' + ctx.AI_API_KEY, 'Content-Type': 'application/json' },
      body: { model: ctx.AI_MODEL, response_format: { type: 'json_object' },
        messages: [{ role: 'system', content: 'Devuelve JSON valido.' }, { role: 'user', content: 'Genera 60 combinaciones de compatibilidad con campos inversor, bateria, cargador_ev, compatible(boolean). Devuelve {"items":[...]}.' }] },
      json: true
    });
    return JSON.parse(resp.choices?.[0]?.message?.content || '{}').items || [];
  } catch (e) { console.warn(JSON.stringify({ stage: 'COMPAT_AI_FALLBACK_ERROR', error: e.message })); return []; }
}

let records = [];
const dead = [];

const lines = String(raw).split('\n').filter(l => l.trim());
if (lines.length >= 2) {
  const headers = lines[0].split(',').map(h => h.trim().toLowerCase().replace(/[^a-z_]/g, '_'));
  for (const line of lines.slice(1)) {
    const vals = line.split(',');
    const obj = {};
    headers.forEach((h, i) => obj[h] = (vals[i] || '').trim());
    const inversor = String(obj.inversor || '').trim();
    const bateria = String(obj.bateria || '').trim();
    const cargadorEv = String(obj.cargador_ev || '').trim();
    if (!inversor || !bateria || !cargadorEv) { dead.push({ ...obj, _error: 'Clave compuesta incompleta' }); continue; }
    records.push({ inversor, bateria, cargador_ev: cargadorEv, compatible: toBool(obj.compatible) });
  }
}

if (!records.length) {
  const aiRecords = await aiCompatFallback();
  console.log(JSON.stringify({ stage: 'COMPAT_AI_FALLBACK_USED', generated: aiRecords.length }));
  if (ctx.STRICT_PROD) {
    staticData.strictAlerts = staticData.strictAlerts || [];
    staticData.strictAlerts.push({ stage: 'COMPAT', reason: 'Fuente CSV oficial vacía', aiDraftCount: aiRecords.length, timestamp: new Date().toISOString() });
    return [];
  }
  records = aiRecords.map(r => ({ inversor: String(r.inversor||'').trim(), bateria: String(r.bateria||'').trim(), cargador_ev: String(r.cargador_ev||'').trim(), compatible: !!r.compatible })).filter(r => r.inversor && r.bateria && r.cargador_ev);
}

await upsertDeadLetter(dead, 'COMPAT_PARSE');
console.log(JSON.stringify({ stage: 'COMPAT_PARSE', valid: records.length, dead: dead.length }));
return records.map(r => ({ json: { ...ctx, record: r } }));

