    });
    console.log(JSON.stringify({ stage: `REBUILD_${name}`, status: r.statusCode || 'ok' }));
  } catch (e) {
    // FIX: no fallar silencioso – registra en dead_letters
    console.error(JSON.stringify({ stage: `REBUILD_${name}_ERROR`, error: e.message }));
    await $helpers.httpRequest({
