/*
── SQL sugerido para las RPCs ──────────────────────────────────────────
CREATE OR REPLACE FUNCTION rebuild_municipios_energia() RETURNS void AS $$
  INSERT INTO municipios_energia (municipio, provincia, slug, irradiacion_kwh_m2, precio_kwh, ahorro_estimado_anual)
  SELECT m.nombre_municipio, m.nombre_provincia, m.slug,
         r.irradiacion_kwh_m2,
         t.precio_kwh_media,
         ROUND((r.irradiacion_kwh_m2 * 4 * 0.80 * t.precio_kwh_media)::numeric, 2) AS ahorro_estimado_anual
  FROM municipios_dataset_es m
  LEFT JOIN radiacion_solar_provincial_es r ON r.provincia = m.nombre_provincia
  LEFT JOIN LATERAL (
    SELECT precio_kwh_media FROM precios_electricidad_es
    ORDER BY fecha DESC LIMIT 1
  ) t ON true
  ON CONFLICT (slug) DO UPDATE SET
    irradiacion_kwh_m2 = EXCLUDED.irradiacion_kwh_m2,
    precio_kwh = EXCLUDED.precio_kwh,
    ahorro_estimado_anual = EXCLUDED.ahorro_estimado_anual,
    updated_at = now();
$$ LANGUAGE SQL;
*/

// FIX: on_conflict ahora incluye columna de conflicto explícita (slug)
const ctx = $('INIT – Env & Config').first().json;
if (ctx.DRY_RUN) return [{ json: ctx }];

try {
  const data = await $helpers.httpRequest({
    method: 'GET',
    url: `${ctx.SUPABASE_URL}/rest/v1/municipios_energia?select=municipio,provincia,slug,irradiacion_kwh_m2,precio_kwh&limit=10000`,
    headers: { 'apikey': ctx.SUPABASE_SERVICE_ROLE_KEY, 'Authorization': `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}` }
  });

  const municipios = Array.isArray(data) ? data : [];

  if (!municipios.length) {
    console.warn(JSON.stringify({ stage: 'ESTIMACIONES_EMPTY', msg: 'municipios_energia vacía – ¿REBUILD falló?' }));
    await $helpers.httpRequest({
      method: 'POST', url: `${ctx.SUPABASE_URL}/rest/v1/etl_dead_letters`,
      headers: { 'apikey': ctx.SUPABASE_SERVICE_ROLE_KEY, 'Authorization': `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify([{ run_id: ctx.runId, stage: 'ESTIMACIONES_EMPTY', payload: '{}', error: 'municipios_energia vacía tras REBUILD', created_at: new Date().toISOString() }])
    }).catch(() => {});
    return [{ json: ctx }];
  }

  const estimaciones = municipios.map(m => ({
    municipio: m.municipio,
    provincia: m.provincia,
    slug: m.slug,
    potencia_instalada_kwp: 4,
    produccion_anual_kwh: Math.round((m.irradiacion_kwh_m2 || 1300) * 4 * 0.80),
    precio_kwh_referencia: m.precio_kwh || 0.15,
    ahorro_bruto_anual_eur: Math.round((m.irradiacion_kwh_m2 || 1300) * 4 * 0.80 * (m.precio_kwh || 0.15)),
    payback_estimado_anios: Math.round(6000 / Math.max((m.irradiacion_kwh_m2 || 1300) * 4 * 0.80 * (m.precio_kwh || 0.15), 1)),
    actualizado_en: new Date().toISOString()
  }));

  // FIX: on_conflict especifica columna explícita
  for (let i = 0; i < estimaciones.length; i += 500) {
    const batch = estimaciones.slice(i, i + 500);
    await $helpers.httpRequest({
      method: 'POST',
      url: `${ctx.SUPABASE_URL}/rest/v1/estimaciones_ahorro_anual_es?on_conflict=slug`,
      headers: { 'apikey': ctx.SUPABASE_SERVICE_ROLE_KEY, 'Authorization': `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'resolution=merge-duplicates,return=minimal' },
      body: JSON.stringify(batch)
    });
  }

  console.log(JSON.stringify({ stage: 'ESTIMACIONES_UPSERT', count: estimaciones.length }));
} catch (e) {
  console.error(JSON.stringify({ stage: 'ESTIMACIONES_ERROR', error: e.message }));
}

return [{ json: ctx }];

